class Solution:
    def compress(self, chars: List[str]) -> int:
        if not chars:
            return 0
        i, anchor = 0, 0
        for i, c in enumerate(chars):
            if i == len(chars) - 1 or chars[i] != chars[i + 1]:
                chars[anchor] = chars[i]
                anchor += 1
                if i > anchor - 1:
                    for digit in str(i - anchor + 1):
                        chars[anchor] = digit
                        anchor += 1
        return anchor
